from pathlib import Path
seqs={}
name=None
for line in Path('sequences.fasta').read_text().splitlines():
    if line.startswith('>'):
        name=line[1:].strip(); seqs[name]=''
    else:
        seqs[name]+=line.strip().lower()
output=seqs['output']
for name in ['egfp','flag','snap']:
    s=seqs[name]
    best=[]
    maxlen=0
    for i in range(len(s)):
        # could optimize by decreasing j; okay small
        for j in range(len(s),i,-1):
            l=j-i
            if l<maxlen: break
            sub=s[i:j]
            pos=output.find(sub)
            if pos!=-1:
                if l>maxlen:
                    maxlen=l; best=[(i,j,pos)]
                elif l==maxlen:
                    best.append((i,j,pos))
                break
    print(name,'maxlen',maxlen,'matches',best[:10],'count',len(best))
